225	static ngx_inline void
226	ngx_quic_bpf_close(ngx_log_t *log, int fd, const char *name)
227	{
228	    if (close(fd) != -1) {
229	        return;
230	    }
231	
232	    ngx_log_error(NGX_LOG_EMERG, log, ngx_errno,
233	                  "quic bpf close %s fd:%d failed", name, fd);
234	}
