59	ngx_int_t
60	ngx_quic_ciphers(ngx_uint_t id, ngx_quic_ciphers_t *ciphers)
61	{
62	    ngx_int_t  len;
63	
64	    switch (id) {
65	
66	    case TLS1_3_CK_AES_128_GCM_SHA256:
67	#if (NGX_QUIC_BORINGSSL_EVP_API)
68	        ciphers->c = EVP_aead_aes_128_gcm();
69	#else
70	        ciphers->c = EVP_aes_128_gcm();
71	#endif
72	        ciphers->hp = EVP_aes_128_ctr();
73	        ciphers->d = EVP_sha256();
74	        len = 16;
75	        break;
76	
77	    case TLS1_3_CK_AES_256_GCM_SHA384:
78	#if (NGX_QUIC_BORINGSSL_EVP_API)
79	        ciphers->c = EVP_aead_aes_256_gcm();
80	#else
81	        ciphers->c = EVP_aes_256_gcm();
82	#endif
83	        ciphers->hp = EVP_aes_256_ctr();
84	        ciphers->d = EVP_sha384();
85	        len = 32;
86	        break;
87	
88	    case TLS1_3_CK_CHACHA20_POLY1305_SHA256:
89	#if (NGX_QUIC_BORINGSSL_EVP_API)
90	        ciphers->c = EVP_aead_chacha20_poly1305();
91	#else
92	        ciphers->c = EVP_chacha20_poly1305();
93	#endif
94	#if (NGX_QUIC_BORINGSSL_EVP_API)
95	        ciphers->hp = (const EVP_CIPHER *) EVP_aead_chacha20_poly1305();
96	#else
97	        ciphers->hp = EVP_chacha20();
98	#endif
99	        ciphers->d = EVP_sha256();
100	        len = 32;
101	        break;
102	
103	#if !(NGX_QUIC_BORINGSSL_EVP_API)
104	    case TLS1_3_CK_AES_128_CCM_SHA256:
105	        ciphers->c = EVP_aes_128_ccm();
106	        ciphers->hp = EVP_aes_128_ctr();
107	        ciphers->d = EVP_sha256();
108	        len = 16;
109	        break;
110	#endif
111	
112	    default:
113	        return NGX_ERROR;
114	    }
115	
116	    return len;
117	}
