120	ngx_int_t
121	ngx_quic_keys_set_initial_secret(ngx_quic_keys_t *keys, ngx_str_t *secret,
122	    ngx_log_t *log)
123	{
124	    size_t               is_len;
125	    uint8_t              is[SHA256_DIGEST_LENGTH];
126	    ngx_str_t            iss;
127	    ngx_uint_t           i;
128	    const EVP_MD        *digest;
129	    ngx_quic_md_t        client_key, server_key;
130	    ngx_quic_hkdf_t      seq[8];
131	    ngx_quic_secret_t   *client, *server;
132	    ngx_quic_ciphers_t   ciphers;
133	
134	    static const uint8_t salt[20] = {
135	        0x38, 0x76, 0x2c, 0xf7, 0xf5, 0x59, 0x34, 0xb3, 0x4d, 0x17,
136	        0x9a, 0xe6, 0xa4, 0xc8, 0x0c, 0xad, 0xcc, 0xbb, 0x7f, 0x0a
137	    };
138	
139	    client = &keys->secrets[NGX_QUIC_ENCRYPTION_INITIAL].client;
140	    server = &keys->secrets[NGX_QUIC_ENCRYPTION_INITIAL].server;
141	
142	    /*
143	     * RFC 9001, section 5.  Packet Protection
144	     *
145	     * Initial packets use AEAD_AES_128_GCM.  The hash function
146	     * for HKDF when deriving initial secrets and keys is SHA-256.
147	     */
148	
149	    digest = EVP_sha256();
150	    is_len = SHA256_DIGEST_LENGTH;
151	
152	    if (ngx_hkdf_extract(is, &is_len, digest, secret->data, secret->len,
153	                         salt, sizeof(salt))
154	        != NGX_OK)
155	    {
156	        return NGX_ERROR;
157	    }
158	
159	    iss.len = is_len;
160	    iss.data = is;
161	
162	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, log, 0,
163	                   "quic ngx_quic_set_initial_secret");
164	#ifdef NGX_QUIC_DEBUG_CRYPTO
165	    ngx_log_debug3(NGX_LOG_DEBUG_EVENT, log, 0,
166	                   "quic salt len:%uz %*xs", sizeof(salt), sizeof(salt), salt);
167	    ngx_log_debug3(NGX_LOG_DEBUG_EVENT, log, 0,
168	                   "quic initial secret len:%uz %*xs", is_len, is_len, is);
169	#endif
170	
171	    client->secret.len = SHA256_DIGEST_LENGTH;
172	    server->secret.len = SHA256_DIGEST_LENGTH;
173	
174	    client_key.len = NGX_QUIC_AES_128_KEY_LEN;
175	    server_key.len = NGX_QUIC_AES_128_KEY_LEN;
176	
177	    client->hp.len = NGX_QUIC_AES_128_KEY_LEN;
178	    server->hp.len = NGX_QUIC_AES_128_KEY_LEN;
179	
180	    client->iv.len = NGX_QUIC_IV_LEN;
181	    server->iv.len = NGX_QUIC_IV_LEN;
182	
183	    /* labels per RFC 9001, 5.1. Packet Protection Keys */
184	    ngx_quic_hkdf_set(&seq[0], "tls13 client in", &client->secret, &iss);
185	    ngx_quic_hkdf_set(&seq[1], "tls13 quic key", &client_key, &client->secret);
186	    ngx_quic_hkdf_set(&seq[2], "tls13 quic iv", &client->iv, &client->secret);
187	    ngx_quic_hkdf_set(&seq[3], "tls13 quic hp", &client->hp, &client->secret);
188	    ngx_quic_hkdf_set(&seq[4], "tls13 server in", &server->secret, &iss);
189	    ngx_quic_hkdf_set(&seq[5], "tls13 quic key", &server_key, &server->secret);
190	    ngx_quic_hkdf_set(&seq[6], "tls13 quic iv", &server->iv, &server->secret);
191	    ngx_quic_hkdf_set(&seq[7], "tls13 quic hp", &server->hp, &server->secret);
192	
193	    for (i = 0; i < (sizeof(seq) / sizeof(seq[0])); i++) {
194	        if (ngx_quic_hkdf_expand(&seq[i], digest, log) != NGX_OK) {
195	            return NGX_ERROR;
196	        }
197	    }
198	
199	    if (ngx_quic_ciphers(NGX_QUIC_INITIAL_CIPHER, &ciphers) == NGX_ERROR) {
200	        return NGX_ERROR;
201	    }
202	
203	    if (ngx_quic_crypto_init(ciphers.c, client, &client_key, 0, log)
204	        == NGX_ERROR)
205	    {
206	        return NGX_ERROR;
207	    }
208	
209	    if (ngx_quic_crypto_init(ciphers.c, server, &server_key, 1, log)
210	        == NGX_ERROR)
211	    {
212	        goto failed;
213	    }
214	
215	    if (ngx_quic_crypto_hp_init(ciphers.hp, client, log) == NGX_ERROR) {
216	        goto failed;
217	    }
218	
219	    if (ngx_quic_crypto_hp_init(ciphers.hp, server, log) == NGX_ERROR) {
220	        goto failed;
221	    }
222	
223	    return NGX_OK;
224	
225	failed:
226	
227	    ngx_quic_keys_cleanup(keys);
228	
229	    return NGX_ERROR;
230	}
