233	ngx_int_t
234	ngx_quic_hkdf_expand(ngx_quic_hkdf_t *h, const EVP_MD *digest, ngx_log_t *log)
235	{
236	    size_t    info_len;
237	    uint8_t  *p;
238	    uint8_t   info[20];
239	
240	    info_len = 2 + 1 + h->label_len + 1;
241	
242	    info[0] = 0;
243	    info[1] = h->out_len;
244	    info[2] = h->label_len;
245	
246	    p = ngx_cpymem(&info[3], h->label, h->label_len);
247	    *p = '\0';
248	
249	    if (ngx_hkdf_expand(h->out, h->out_len, digest,
250	                        h->prk, h->prk_len, info, info_len)
251	        != NGX_OK)
252	    {
253	        ngx_ssl_error(NGX_LOG_INFO, log, 0,
254	                      "ngx_hkdf_expand(%*s) failed", h->label_len, h->label);
255	        return NGX_ERROR;
256	    }
257	
258	#ifdef NGX_QUIC_DEBUG_CRYPTO
259	    ngx_log_debug5(NGX_LOG_DEBUG_EVENT, log, 0,
260	                   "quic expand \"%*s\" len:%uz %*xs",
261	                   h->label_len, h->label, h->out_len, h->out_len, h->out);
262	#endif
263	
264	    return NGX_OK;
265	}
