268	static ngx_int_t
269	ngx_hkdf_expand(u_char *out_key, size_t out_len, const EVP_MD *digest,
270	    const uint8_t *prk, size_t prk_len, const u_char *info, size_t info_len)
271	{
272	#if (NGX_QUIC_BORINGSSL_EVP_API)
273	
274	    if (HKDF_expand(out_key, out_len, digest, prk, prk_len, info, info_len)
275	        == 0)
276	    {
277	        return NGX_ERROR;
278	    }
279	
280	    return NGX_OK;
281	
282	#else
283	
284	    EVP_PKEY_CTX  *pctx;
285	
286	    pctx = EVP_PKEY_CTX_new_id(EVP_PKEY_HKDF, NULL);
287	    if (pctx == NULL) {
288	        return NGX_ERROR;
289	    }
290	
291	    if (EVP_PKEY_derive_init(pctx) <= 0) {
292	        goto failed;
293	    }
294	
295	    if (EVP_PKEY_CTX_hkdf_mode(pctx, EVP_PKEY_HKDEF_MODE_EXPAND_ONLY) <= 0) {
296	        goto failed;
297	    }
298	
299	    if (EVP_PKEY_CTX_set_hkdf_md(pctx, digest) <= 0) {
300	        goto failed;
301	    }
302	
303	    if (EVP_PKEY_CTX_set1_hkdf_key(pctx, prk, prk_len) <= 0) {
304	        goto failed;
305	    }
306	
307	    if (EVP_PKEY_CTX_add1_hkdf_info(pctx, info, info_len) <= 0) {
308	        goto failed;
309	    }
310	
311	    if (EVP_PKEY_derive(pctx, out_key, &out_len) <= 0) {
312	        goto failed;
313	    }
314	
315	    EVP_PKEY_CTX_free(pctx);
316	
317	    return NGX_OK;
318	
319	failed:
320	
321	    EVP_PKEY_CTX_free(pctx);
322	
323	    return NGX_ERROR;
324	
325	#endif
326	}
