328	
329	static ngx_int_t
330	ngx_hkdf_extract(u_char *out_key, size_t *out_len, const EVP_MD *digest,
331	    const u_char *secret, size_t secret_len, const u_char *salt,
332	    size_t salt_len)
333	{
334	#if (NGX_QUIC_BORINGSSL_EVP_API)
335	
336	    if (HKDF_extract(out_key, out_len, digest, secret, secret_len, salt,
337	                     salt_len)
338	        == 0)
339	    {
340	        return NGX_ERROR;
341	    }
342	
343	    return NGX_OK;
344	
345	#else
346	
347	    EVP_PKEY_CTX  *pctx;
348	
349	    pctx = EVP_PKEY_CTX_new_id(EVP_PKEY_HKDF, NULL);
350	    if (pctx == NULL) {
351	        return NGX_ERROR;
352	    }
353	
354	    if (EVP_PKEY_derive_init(pctx) <= 0) {
355	        goto failed;
356	    }
357	
358	    if (EVP_PKEY_CTX_hkdf_mode(pctx, EVP_PKEY_HKDEF_MODE_EXTRACT_ONLY) <= 0) {
359	        goto failed;
360	    }
361	
362	    if (EVP_PKEY_CTX_set_hkdf_md(pctx, digest) <= 0) {
363	        goto failed;
364	    }
365	
366	    if (EVP_PKEY_CTX_set1_hkdf_key(pctx, secret, secret_len) <= 0) {
367	        goto failed;
368	    }
369	
370	    if (EVP_PKEY_CTX_set1_hkdf_salt(pctx, salt, salt_len) <= 0) {
371	        goto failed;
372	    }
373	
374	    if (EVP_PKEY_derive(pctx, out_key, out_len) <= 0) {
375	        goto failed;
376	    }
377	
378	    EVP_PKEY_CTX_free(pctx);
379	
380	    return NGX_OK;
381	
382	failed:
383	
384	    EVP_PKEY_CTX_free(pctx);
385	
386	    return NGX_ERROR;
387	
388	#endif
389	}
