392	ngx_int_t
393	ngx_quic_crypto_init(const ngx_quic_cipher_t *cipher, ngx_quic_secret_t *s,
394	    ngx_quic_md_t *key, ngx_int_t enc, ngx_log_t *log)
395	{
396	
397	#if (NGX_QUIC_BORINGSSL_EVP_API)
398	    EVP_AEAD_CTX  *ctx;
399	
400	    ctx = EVP_AEAD_CTX_new(cipher, key->data, key->len,
401	                           EVP_AEAD_DEFAULT_TAG_LENGTH);
402	    if (ctx == NULL) {
403	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_AEAD_CTX_new() failed");
404	        return NGX_ERROR;
405	    }
406	#else
407	    EVP_CIPHER_CTX  *ctx;
408	
409	    ctx = EVP_CIPHER_CTX_new();
410	    if (ctx == NULL) {
411	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CIPHER_CTX_new() failed");
412	        return NGX_ERROR;
413	    }
414	
415	    if (EVP_CipherInit_ex(ctx, cipher, NULL, NULL, NULL, enc) != 1) {
416	        EVP_CIPHER_CTX_free(ctx);
417	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherInit_ex() failed");
418	        return NGX_ERROR;
419	    }
420	
421	    if (EVP_CIPHER_mode(cipher) == EVP_CIPH_CCM_MODE
422	        && EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_AEAD_SET_TAG, NGX_QUIC_TAG_LEN,
423	                               NULL)
424	           == 0)
425	    {
426	        EVP_CIPHER_CTX_free(ctx);
427	        ngx_ssl_error(NGX_LOG_INFO, log, 0,
428	                      "EVP_CIPHER_CTX_ctrl(EVP_CTRL_AEAD_SET_TAG) failed");
429	        return NGX_ERROR;
430	    }
431	
432	    if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_AEAD_SET_IVLEN, s->iv.len, NULL)
433	        == 0)
434	    {
435	        EVP_CIPHER_CTX_free(ctx);
436	        ngx_ssl_error(NGX_LOG_INFO, log, 0,
437	                      "EVP_CIPHER_CTX_ctrl(EVP_CTRL_AEAD_SET_IVLEN) failed");
438	        return NGX_ERROR;
439	    }
440	
441	    if (EVP_CipherInit_ex(ctx, NULL, NULL, key->data, NULL, enc) != 1) {
442	        EVP_CIPHER_CTX_free(ctx);
443	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherInit_ex() failed");
444	        return NGX_ERROR;
445	    }
446	#endif
447	
448	    s->ctx = ctx;
449	    return NGX_OK;
450	}
