494	
495	static ngx_int_t
496	ngx_quic_crypto_common(ngx_quic_secret_t *s, ngx_str_t *out,
497	    const u_char *nonce, ngx_str_t *in, ngx_str_t *ad, ngx_log_t *log)
498	{
499	    int                     len, enc;
500	    ngx_quic_crypto_ctx_t  *ctx;
501	
502	    ctx = s->ctx;
503	    enc = EVP_CIPHER_CTX_encrypting(ctx);
504	
505	    if (EVP_CipherInit_ex(ctx, NULL, NULL, NULL, nonce, enc) != 1) {
506	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherInit_ex() failed");
507	        return NGX_ERROR;
508	    }
509	
510	    if (enc == 0) {
511	        in->len -= NGX_QUIC_TAG_LEN;
512	
513	        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_AEAD_SET_TAG, NGX_QUIC_TAG_LEN,
514	                                in->data + in->len)
515	            == 0)
516	        {
517	            ngx_ssl_error(NGX_LOG_INFO, log, 0,
518	                          "EVP_CIPHER_CTX_ctrl(EVP_CTRL_AEAD_SET_TAG) failed");
519	            return NGX_ERROR;
520	        }
521	    }
522	
523	    if (EVP_CIPHER_mode(EVP_CIPHER_CTX_cipher(ctx)) == EVP_CIPH_CCM_MODE
524	        && EVP_CipherUpdate(ctx, NULL, &len, NULL, in->len) != 1)
525	    {
526	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherUpdate() failed");
527	        return NGX_ERROR;
528	    }
529	
530	    if (EVP_CipherUpdate(ctx, NULL, &len, ad->data, ad->len) != 1) {
531	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherUpdate() failed");
532	        return NGX_ERROR;
533	    }
534	
535	    if (EVP_CipherUpdate(ctx, out->data, &len, in->data, in->len) != 1) {
536	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherUpdate() failed");
537	        return NGX_ERROR;
538	    }
539	
540	    out->len = len;
541	
542	    if (EVP_CipherFinal_ex(ctx, out->data + out->len, &len) <= 0) {
543	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CipherFinal_ex failed");
544	        return NGX_ERROR;
545	    }
546	
547	    out->len += len;
548	
549	    if (enc == 1) {
550	        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_AEAD_GET_TAG, NGX_QUIC_TAG_LEN,
551	                                out->data + out->len)
552	            == 0)
553	        {
554	            ngx_ssl_error(NGX_LOG_INFO, log, 0,
555	                          "EVP_CIPHER_CTX_ctrl(EVP_CTRL_AEAD_GET_TAG) failed");
556	            return NGX_ERROR;
557	        }
558	
559	        out->len += NGX_QUIC_TAG_LEN;
560	    }
561	
562	    return NGX_OK;
563	}
