582	static ngx_int_t
583	ngx_quic_crypto_hp_init(const EVP_CIPHER *cipher, ngx_quic_secret_t *s,
584	    ngx_log_t *log)
585	{
586	    EVP_CIPHER_CTX  *ctx;
587	
588	#if (NGX_QUIC_BORINGSSL_EVP_API)
589	    if (cipher == (EVP_CIPHER *) EVP_aead_chacha20_poly1305()) {
590	        /* no EVP interface */
591	        s->hp_ctx = NULL;
592	        return NGX_OK;
593	    }
594	#endif
595	
596	    ctx = EVP_CIPHER_CTX_new();
597	    if (ctx == NULL) {
598	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_CIPHER_CTX_new() failed");
599	        return NGX_ERROR;
600	    }
601	
602	    if (EVP_EncryptInit_ex(ctx, cipher, NULL, s->hp.data, NULL) != 1) {
603	        EVP_CIPHER_CTX_free(ctx);
604	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_EncryptInit_ex() failed");
605	        return NGX_ERROR;
606	    }
607	
608	    s->hp_ctx = ctx;
609	    return NGX_OK;
610	}
