613	static ngx_int_t
614	ngx_quic_crypto_hp(ngx_quic_secret_t *s, u_char *out, u_char *in,
615	    ngx_log_t *log)
616	{
617	    int              outlen;
618	    EVP_CIPHER_CTX  *ctx;
619	
620	    static const u_char zero[NGX_QUIC_HP_LEN];
621	
622	    ctx = s->hp_ctx;
623	
624	#if (NGX_QUIC_BORINGSSL_EVP_API)
625	    uint32_t         cnt;
626	
627	    if (ctx == NULL) {
628	        ngx_memcpy(&cnt, in, sizeof(uint32_t));
629	        CRYPTO_chacha_20(out, zero, NGX_QUIC_HP_LEN, s->hp.data, &in[4], cnt);
630	        return NGX_OK;
631	    }
632	#endif
633	
634	    if (EVP_EncryptInit_ex(ctx, NULL, NULL, NULL, in) != 1) {
635	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_EncryptInit_ex() failed");
636	        return NGX_ERROR;
637	    }
638	
639	    if (!EVP_EncryptUpdate(ctx, out, &outlen, zero, NGX_QUIC_HP_LEN)) {
640	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_EncryptUpdate() failed");
641	        return NGX_ERROR;
642	    }
643	
644	    if (!EVP_EncryptFinal_ex(ctx, out + NGX_QUIC_HP_LEN, &outlen)) {
645	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "EVP_EncryptFinal_Ex() failed");
646	        return NGX_ERROR;
647	    }
648	
649	    return NGX_OK;
650	}
