663	ngx_int_t
664	ngx_quic_keys_set_encryption_secret(ngx_log_t *log, ngx_uint_t is_write,
665	    ngx_quic_keys_t *keys, ngx_uint_t level, const SSL_CIPHER *cipher,
666	    const uint8_t *secret, size_t secret_len)
667	{
668	    ngx_int_t            key_len;
669	    ngx_str_t            secret_str;
670	    ngx_uint_t           i;
671	    ngx_quic_md_t        key;
672	    ngx_quic_hkdf_t      seq[3];
673	    ngx_quic_secret_t   *peer_secret;
674	    ngx_quic_ciphers_t   ciphers;
675	
676	    peer_secret = is_write ? &keys->secrets[level].server
677	                           : &keys->secrets[level].client;
678	
679	    keys->cipher = SSL_CIPHER_get_id(cipher);
680	
681	    key_len = ngx_quic_ciphers(keys->cipher, &ciphers);
682	
683	    if (key_len == NGX_ERROR) {
684	        ngx_ssl_error(NGX_LOG_INFO, log, 0, "unexpected cipher");
685	        return NGX_ERROR;
686	    }
687	
688	    if (sizeof(peer_secret->secret.data) < secret_len) {
689	        ngx_log_error(NGX_LOG_ALERT, log, 0,
690	                      "unexpected secret len: %uz", secret_len);
691	        return NGX_ERROR;
692	    }
693	
694	    peer_secret->secret.len = secret_len;
695	    ngx_memcpy(peer_secret->secret.data, secret, secret_len);
696	
697	    key.len = key_len;
698	    peer_secret->iv.len = NGX_QUIC_IV_LEN;
699	    peer_secret->hp.len = key_len;
700	
701	    secret_str.len = secret_len;
702	    secret_str.data = (u_char *) secret;
703	
704	    ngx_quic_hkdf_set(&seq[0], "tls13 quic key", &key, &secret_str);
705	    ngx_quic_hkdf_set(&seq[1], "tls13 quic iv", &peer_secret->iv, &secret_str);
706	    ngx_quic_hkdf_set(&seq[2], "tls13 quic hp", &peer_secret->hp, &secret_str);
707	
708	    for (i = 0; i < (sizeof(seq) / sizeof(seq[0])); i++) {
709	        if (ngx_quic_hkdf_expand(&seq[i], ciphers.d, log) != NGX_OK) {
710	            return NGX_ERROR;
711	        }
712	    }
713	
714	    if (ngx_quic_crypto_init(ciphers.c, peer_secret, &key, is_write, log)
715	        == NGX_ERROR)
716	    {
717	        return NGX_ERROR;
718	    }
719	
720	    if (ngx_quic_crypto_hp_init(ciphers.hp, peer_secret, log) == NGX_ERROR) {
721	        return NGX_ERROR;
722	    }
723	
724	    ngx_explicit_memzero(key.data, key.len);
725	
726	    return NGX_OK;
727	}
