785	void
786	ngx_quic_keys_update(ngx_event_t *ev)
787	{
788	    ngx_int_t               key_len;
789	    ngx_uint_t              i;
790	    ngx_quic_md_t           client_key, server_key;
791	    ngx_quic_hkdf_t         seq[6];
792	    ngx_quic_keys_t        *keys;
793	    ngx_connection_t       *c;
794	    ngx_quic_ciphers_t      ciphers;
795	    ngx_quic_secrets_t     *current, *next;
796	    ngx_quic_connection_t  *qc;
797	
798	    c = ev->data;
799	    qc = ngx_quic_get_connection(c);
800	    keys = qc->keys;
801	
802	    current = &keys->secrets[NGX_QUIC_ENCRYPTION_APPLICATION];
803	    next = &keys->next_key;
804	
805	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, c->log, 0, "quic key update");
806	
807	    c->log->action = "updating keys";
808	
809	    key_len = ngx_quic_ciphers(keys->cipher, &ciphers);
810	
811	    if (key_len == NGX_ERROR) {
812	        goto failed;
813	    }
814	
815	    client_key.len = key_len;
816	    server_key.len = key_len;
817	
818	    next->client.secret.len = current->client.secret.len;
819	    next->client.iv.len = NGX_QUIC_IV_LEN;
820	    next->client.hp = current->client.hp;
821	    next->client.hp_ctx = current->client.hp_ctx;
822	
823	    next->server.secret.len = current->server.secret.len;
824	    next->server.iv.len = NGX_QUIC_IV_LEN;
825	    next->server.hp = current->server.hp;
826	    next->server.hp_ctx = current->server.hp_ctx;
827	
828	    ngx_quic_hkdf_set(&seq[0], "tls13 quic ku",
829	                      &next->client.secret, &current->client.secret);
830	    ngx_quic_hkdf_set(&seq[1], "tls13 quic key",
831	                      &client_key, &next->client.secret);
832	    ngx_quic_hkdf_set(&seq[2], "tls13 quic iv",
833	                      &next->client.iv, &next->client.secret);
834	    ngx_quic_hkdf_set(&seq[3], "tls13 quic ku",
835	                      &next->server.secret, &current->server.secret);
836	    ngx_quic_hkdf_set(&seq[4], "tls13 quic key",
837	                      &server_key, &next->server.secret);
838	    ngx_quic_hkdf_set(&seq[5], "tls13 quic iv",
839	                      &next->server.iv, &next->server.secret);
840	
841	    for (i = 0; i < (sizeof(seq) / sizeof(seq[0])); i++) {
842	        if (ngx_quic_hkdf_expand(&seq[i], ciphers.d, c->log) != NGX_OK) {
843	            goto failed;
844	        }
845	    }
846	
847	    if (ngx_quic_crypto_init(ciphers.c, &next->client, &client_key, 0, c->log)
848	        == NGX_ERROR)
849	    {
850	        goto failed;
851	    }
852	
853	    if (ngx_quic_crypto_init(ciphers.c, &next->server, &server_key, 1, c->log)
854	        == NGX_ERROR)
855	    {
856	        goto failed;
857	    }
858	
859	    ngx_explicit_memzero(current->client.secret.data,
860	                         current->client.secret.len);
861	    ngx_explicit_memzero(current->server.secret.data,
862	                         current->server.secret.len);
863	
864	    current->client.secret.len = 0;
865	    current->server.secret.len = 0;
866	
867	    ngx_explicit_memzero(client_key.data, client_key.len);
868	    ngx_explicit_memzero(server_key.data, server_key.len);
869	
870	    return;
871	
872	failed:
873	
874	    ngx_quic_close_connection(c, NGX_ERROR);
875	}
