907	static ngx_int_t
908	ngx_quic_create_packet(ngx_quic_header_t *pkt, ngx_str_t *res)
909	{
910	    u_char             *pnp, *sample;
911	    ngx_str_t           ad, out;
912	    ngx_uint_t          i;
913	    ngx_quic_secret_t  *secret;
914	    u_char              nonce[NGX_QUIC_IV_LEN], mask[NGX_QUIC_HP_LEN];
915	
916	    ad.data = res->data;
917	    ad.len = ngx_quic_create_header(pkt, ad.data, &pnp);
918	
919	    out.len = pkt->payload.len + NGX_QUIC_TAG_LEN;
920	    out.data = res->data + ad.len;
921	
922	#ifdef NGX_QUIC_DEBUG_CRYPTO
923	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, pkt->log, 0,
924	                   "quic ad len:%uz %xV", ad.len, &ad);
925	#endif
926	
927	    secret = &pkt->keys->secrets[pkt->level].server;
928	
929	    ngx_memcpy(nonce, secret->iv.data, secret->iv.len);
930	    ngx_quic_compute_nonce(nonce, sizeof(nonce), pkt->number);
931	
932	    if (ngx_quic_crypto_seal(secret, &out, nonce, &pkt->payload, &ad, pkt->log)
933	        != NGX_OK)
934	    {
935	        return NGX_ERROR;
936	    }
937	
938	    sample = &out.data[4 - pkt->num_len];
939	    if (ngx_quic_crypto_hp(secret, mask, sample, pkt->log) != NGX_OK) {
940	        return NGX_ERROR;
941	    }
942	
943	    /* RFC 9001, 5.4.1.  Header Protection Application */
944	    ad.data[0] ^= mask[0] & ngx_quic_pkt_hp_mask(pkt->flags);
945	
946	    for (i = 0; i < pkt->num_len; i++) {
947	        pnp[i] ^= mask[i + 1];
948	    }
949	
950	    res->len = ad.len + out.len;
951	
952	    return NGX_OK;
953	}
