955	
956	static ngx_int_t
957	ngx_quic_create_retry_packet(ngx_quic_header_t *pkt, ngx_str_t *res)
958	{
959	    u_char              *start;
960	    ngx_str_t            ad, itag;
961	    ngx_quic_secret_t    secret;
962	    ngx_quic_ciphers_t   ciphers;
963	
964	    /* 5.8.  Retry Packet Integrity */
965	    static ngx_quic_md_t  key = ngx_quic_md(
