1060	static uint64_t
1061	ngx_quic_parse_pn(u_char **pos, ngx_int_t len, u_char *mask,
1062	    uint64_t *largest_pn)
1063	{
1064	    u_char    *p;
1065	    uint64_t   truncated_pn, expected_pn, candidate_pn;
1066	    uint64_t   pn_nbits, pn_win, pn_hwin, pn_mask;
1067	
1068	    pn_nbits = ngx_min(len * 8, 62);
1069	
1070	    p = *pos;
1071	    truncated_pn = *p++ ^ *mask++;
1072	
1073	    while (--len) {
1074	        truncated_pn = (truncated_pn << 8) + (*p++ ^ *mask++);
1075	    }
1076	
1077	    *pos = p;
1078	
1079	    expected_pn = *largest_pn + 1;
1080	    pn_win = 1ULL << pn_nbits;
1081	    pn_hwin = pn_win / 2;
1082	    pn_mask = pn_win - 1;
1083	
1084	    candidate_pn = (expected_pn & ~pn_mask) | truncated_pn;
1085	
1086	    if ((int64_t) candidate_pn <= (int64_t) (expected_pn - pn_hwin)
1087	        && candidate_pn < (1ULL << 62) - pn_win)
1088	    {
1089	        candidate_pn += pn_win;
1090	
1091	    } else if (candidate_pn > expected_pn + pn_hwin
1092	               && candidate_pn >= pn_win)
1093	    {
1094	        candidate_pn -= pn_win;
1095	    }
1096	
1097	    *largest_pn = ngx_max((int64_t) *largest_pn, (int64_t) candidate_pn);
1098	
1099	    return candidate_pn;
1100	}
