1103	void
1104	ngx_quic_compute_nonce(u_char *nonce, size_t len, uint64_t pn)
1105	{
1106	    nonce[len - 8] ^= (pn >> 56) & 0x3f;
1107	    nonce[len - 7] ^= (pn >> 48) & 0xff;
1108	    nonce[len - 6] ^= (pn >> 40) & 0xff;
1109	    nonce[len - 5] ^= (pn >> 32) & 0xff;
1110	    nonce[len - 4] ^= (pn >> 24) & 0xff;
1111	    nonce[len - 3] ^= (pn >> 16) & 0xff;
1112	    nonce[len - 2] ^= (pn >> 8) & 0xff;
1113	    nonce[len - 1] ^= pn & 0xff;
1114	}
