1193	    pkt->pn = pn;
1194	
1195	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, pkt->log, 0,
1196	                   "quic packet rx clearflags:%xd", pkt->flags);
1197	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, pkt->log, 0,
1198	                   "quic packet rx number:%uL len:%xi", pn, pnl);
1199	
1200	    /* packet protection */
1201	
1202	    in.data = p;
1203	    in.len = len - pnl;
1204	
1205	    ad.len = p - pkt->data;
